// ===== 구글 캘린더 이벤트 파싱 =====
// 제목 형식: '프로젝트 - 할 일' 또는 '할 일'
// 날짜: event.start.dateTime (시간 포함) 또는 event.start.date (종일)

const event = $json;
const title = (event.summary || '').trim();
const startInfo = event.start || {};

// 날짜 파싱
let dateISO, dateLabel;
if (startInfo.dateTime) {
  // ISO 8601 문자열에서 직접 날짜 추출 (UTC 변환 방지)
  // '2026-02-24T05:00:00+09:00' → '2026-02-24'
  dateISO = startInfo.dateTime.split('T')[0];
  const dateParts = dateISO.split('-');
  dateLabel = dateParts[0]+'년 '+parseInt(dateParts[1])+'월 '+parseInt(dateParts[2])+'일';
} else if (startInfo.date) {
  dateISO = startInfo.date;
  const dateParts = startInfo.date.split('-');
  dateLabel = dateParts[0]+'년 '+parseInt(dateParts[1])+'월 '+parseInt(dateParts[2])+'일';
} else {
  const now = new Date();
  const y = now.getFullYear();
  const m = String(now.getMonth()+1).padStart(2,'0');
  const d = String(now.getDate()).padStart(2,'0');
  dateISO = y+'-'+m+'-'+d;
  dateLabel = y+'년 '+parseInt(m)+'월 '+parseInt(d)+'일';
}

// 제목 파싱: '프로젝트 - 할 일' 형식
let project = null;
let todo = title;
const sepIdx = title.indexOf(' - ');
if (sepIdx !== -1) {
  project = title.substring(0, sepIdx).trim();
  todo = title.substring(sepIdx + 3).trim();
}

return [{
  json: {
    todo: todo,
    project: project || '',
    dateISO: dateISO,
    dateLabel: dateLabel,
    calendarEventId: event.id || ''
  }
}];

// 프로젝트 매칭 결과 처리
const prev = $('이벤트 파싱').first().json;
const results = $input.first().json.results || [];

let projectId = null;
let projectName = null;

if (prev.project && results.length > 0) {
  projectId = results[0].id;
  const titleProp = results[0].properties['프로젝트'];
  if (titleProp && titleProp.title && titleProp.title.length > 0) {
    projectName = titleProp.title[0].plain_text;
  }
}

return [{
  json: {
    ...prev,
    projectId,
    projectName: projectName || prev.project,
    projectMatched: !!projectId
  }
}];

// 캘린더 조회 결과 확인
const prev = $('프로젝트 매칭 결과').first().json;
const results = $input.first().json.results || [];

return [{
  json: {
    ...prev,
    calendarId: results.length > 0 ? results[0].id : null,
    calendarExists: results.length > 0
  }
}];

// 캘린더 ID 통합 (기존 또는 새로 생성된 것)
const prev = $('캘린더 확인').first().json;
let calendarId = prev.calendarId;

// 캘린더가 새로 생성된 경우 그 ID 사용
try {
  const created = $('캘린더 생성').first().json;
  if (created && created.id) calendarId = created.id;
} catch(e) {}

return [{
  json: {
    ...prev,
    calendarId
  }
}];
